import { useState } from 'react';
import { useLocation } from 'react-router-dom';
import DestinationCard from '../components/DestinationCards';
import CreateDestination from '../components/DestinationsCreate';
import { GoogleMap, Marker } from '@react-google-maps/api';
import bretagne from '../assets/bretagne.jpg';
import toscane from '../assets/toscane.jpg';
import miami from '../assets/miami.jpg';
import ny from '../assets/ny.jpg';
import sainttropez from '../assets/sainttropez.jpg';
import crete from '../assets/crete.jpg';
import { fetchDestinationsById } from '../mocks/mockDestinations';
import '../styles/GroupDetails.css';
import '../styles/Groups.css';

const mockDestinations = [
  {
    id: 1,
    name: "Bretagne",
    image: bretagne,
    location: { lat: 48.1173, lng: -1.6778 },
    members: ["Alice", "Bob", "Charlie", "David", "Eva", "Frank", "Theo", "Louis", "Chloe"]
  },
  {
    id: 2,
    name: "Toscane",
    image: toscane,
    location: { lat: 43.7696, lng: 11.2558 },
    members: ["Jean", "Marie", "Claire", "Paul", "Julie"]
  },
  {
    id: 3,
    name: "Miami",
    image: miami,
    location: { lat: 25.7617, lng: -80.1918 },
    members: ["Max", "Léa", "Emma", "Nina"]
  },
  {
    id: 4,
    name: "New-York",
    image: ny,
    location: { lat: 40.7128, lng: -74.0060 },
    members: ["Zack", "Nora", "Sam", "Ali", "Ivy", "Noah", "Sophie", "Tom"]
  },
  {
    id: 5,
    name: "Saint-Tropez",
    image: sainttropez,
    location: { lat: 43.2694, lng: 6.6397 },
    members: ["Yasmine", "Hugo"]
  },
  {
    id: 6,
    name: "Crète",
    image: crete,
    location: { lat: 35.2401, lng: 24.8093 },
    members: ["Milo", "Sarah", "Ines"]
  }
];

export default function Destinations() {
  const { state } = useLocation();
  const [showModal, setShowModal] = useState(false);
  const [groups, setDestinations] = useState(mockDestinations);

  const groupMembers = state?.members || [];
  const groupName = state?.groupName || "Nos destinations";

  return (
    <div className="groups-container">
      <div className="groups-header">
        <h1 className="groups-title">{groupName}</h1>

        {groupMembers.length > 0 && (
          <p className="group-members">
            Membres : {groupMembers.join(', ')}
          </p>
        )}

        <button
          className="create-group-button"
          onClick={() => setShowModal(true)}
        >
          Créer une destination
        </button>
      </div>

     
      <GoogleMap
  mapContainerStyle={{
    width: '100%',
    height: '400px',
    marginBottom: '20px',
    borderRadius: '8px'
  }}
  center={{ lat: 48.8566, lng: 2.3522 }} // Centré par défaut sur Paris
  zoom={3}
>
  {groups.map((group, i) =>
    group.location?.lat && group.location?.lng && (
      <Marker
        key={group.id || i}
        position={{ lat: group.location.lat, lng: group.location.lng }}
        title={group.name}
      />
    )
  )}
</GoogleMap>

        

      <div className="groups-grid">
        {groups.map(group => (
          <DestinationCard
            key={group.id}
            id={group.id}
            name={group.name}
            image={group.image}
            price={group.price}
            startDate={group.startDate}
            endDate={group.endDate}
            creator={group.creator}
            comments={group.comments}
          />
        ))}
      </div>

      {showModal && (
        <div className="modal-overlay">
          <div className="modal-content">
            <button className="close-modal" onClick={() => setShowModal(false)}>✖</button>
            <CreateDestination
              onClose={() => setShowModal(false)}
              onCreate={(newGroup) => setDestinations(prev => [...prev, newGroup])}
            />
          </div>
        </div>
      )}
    </div>
  );
}
